import javax.jws.WebService;
import javax.jws.WebMethod;
import javax.jws.WebParam;
import javax.xml.bind.annotation.XmlElement;
import javax.xml.bind.annotation.XmlRootElement;
import java.math.BigDecimal;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.Base64;

@WebService
public class OrderProcessingService {
    
    private static final Map<String, String> VALID_ITEMS = new ConcurrentHashMap<>();
    private static final Set<String> VALID_CURRENCIES = Set.of("USD", "EUR", "GBP");
    private static final String SECRET_KEY = System.getenv("ORDER_SERVICE_SECRET");
    
    static {
        VALID_ITEMS.put("ITEM001", "Laptop");
        VALID_ITEMS.put("ITEM002", "Mouse");
        VALID_ITEMS.put("ITEM003", "Keyboard");
        VALID_ITEMS.put("ITEM004", "Monitor");
    }
    
    @WebMethod
    public OrderResponse processOrder(@WebParam(name = "orderRequest") OrderRequest orderRequest) {
        try {
            validateOrderRequest(orderRequest);
            BigDecimal totalPrice = calculateTotalPrice(orderRequest.getItems());
            String orderHash = generateOrderHash(orderRequest, totalPrice);
            
            OrderResponse response = new OrderResponse();
            response.setOrderId(generateOrderId());
            response.setTotalPrice(totalPrice);
            response.setOrderHash(orderHash);
            response.setStatus("SUCCESS");
            
            return response;
        } catch (Exception e) {
            OrderResponse response = new OrderResponse();
            response.setStatus("ERROR");
            response.setErrorMessage(e.getMessage());
            return response;
        }
    }
    
    private void validateOrderRequest(OrderRequest request) throws Exception {
        if (request == null) {
            throw new Exception("Order request cannot be null");
        }
        
        if (request.getItems() == null || request.getItems().isEmpty()) {
            throw new Exception("Order must contain at least one item");
        }
        
        if (!VALID_CURRENCIES.contains(request.getCurrency())) {
            throw new Exception("Invalid currency specified");
        }
        
        for (OrderItem item : request.getItems()) {
            validateOrderItem(item);
        }
    }
    
    private void validateOrderItem(OrderItem item) throws Exception {
        if (item.getItemId() == null || item.getItemId().trim().isEmpty()) {
            throw new Exception("Item ID cannot be null or empty");
        }
        
        if (!VALID_ITEMS.containsKey(item.getItemId())) {
            throw new Exception("Invalid item ID: " + item.getItemId());
        }
        
        if (item.getPrice() == null || item.getPrice().compareTo(BigDecimal.ZERO) <= 0) {
            throw new Exception("Item price must be positive");
        }
        
        if (item.getQuantity() <= 0) {
            throw new Exception("Item quantity must be positive");
        }
        
        if (item.getPrice().compareTo(new BigDecimal("999999")) > 0) {
            throw new Exception("Item price exceeds maximum allowed value");
        }
    }
    
    private BigDecimal calculateTotalPrice(List<OrderItem> items) {
        BigDecimal total = BigDecimal.ZERO;
        for (OrderItem item : items) {
            BigDecimal itemTotal = item.getPrice().multiply(BigDecimal.valueOf(item.getQuantity()));
            total = total.add(itemTotal);
        }
        return total.setScale(2, BigDecimal.ROUND_HALF_UP);
    }
    
    private String generateOrderHash(OrderRequest request, BigDecimal totalPrice) throws Exception {
        StringBuilder sb = new StringBuilder();
        sb.append(request.getCurrency());
        sb.append(totalPrice.toString());
        
        for (OrderItem item : request.getItems()) {
            sb.append(item.getItemId());
            sb.append(item.getPrice().toString());
            sb.append(item.getQuantity());
        }
        
        sb.append(SECRET_KEY);
        
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] hashBytes = digest.digest(sb.toString().getBytes());
        return Base64.getEncoder().encodeToString(hashBytes);
    }
    
    private String generateOrderId() {
        return "ORD-" + System.currentTimeMillis() + "-" + UUID.randomUUID().toString().substring(0, 8);
    }
}

